class Solution(object):
    def xorAllNums(self, nums1, nums2):
        m, n = len(nums1), len(nums2)
        xor1 = xor2 = 0
        if n % 2 == 1:
            for num in nums1:
                xor1 ^= num
        if m % 2 == 1:
            for num in nums2:
                xor2 ^= num
        return xor1 ^ xor2
